2908 struct ShuffleOperandCompaction {
2909   /// The cost difference between compacted and original operand. Used to avoid
2910   /// compactions that increase cost. Zero if compaction cannot be applied, but
2911   /// note that valid compactions may also have zero cost.
2912   InstructionCost Cost;
2913   /// The minimal width required for the compacted vector.
2914   unsigned CompactedWidth;
