2920 /// Attempt to narrow/compact a constant vector used in a shuffle by removing
2921 /// elements that are not referenced by the shuffle mask.
2922 static ShuffleOperandCompaction
2923 compactShuffleOperand(Constant *ShuffleInput,
2924                       MutableArrayRef<int> UserShuffleMask, int IndexStart) {
2925   auto *VecTy = cast<FixedVectorType>(ShuffleInput->getType());
2926   unsigned Width = VecTy->getNumElements();
2927 
2928   // Collect only the constant elements that are actually used.
2929   SmallVector<Constant *, 16> CompactedElts;
2930   // Map from original element index to compacted index.
2931   SmallVector<int, 16> IndexRemap(Width, -1);
2932 
2933   // Track whether used elements are already compacted at the front. Even if
2934   // true, we may still shrink this operand by not re-adding trailing poison.
2935   bool AlreadyCompacted = true;
2936 
2937   // This modifies UserShuffleMask, so we cannot back out of transforming the
2938   // operand while proceeding with compactShuffleOperands on the instruction.
2939   for (int &MaskElt : UserShuffleMask) {
2940     if (MaskElt >= IndexStart && MaskElt < IndexStart + (int)Width) {
2941       int RelMaskElt = MaskElt - IndexStart;
2942       if (IndexRemap[RelMaskElt] < 0) {
2943         IndexRemap[RelMaskElt] = CompactedElts.size() + IndexStart;
2944         CompactedElts.push_back(ShuffleInput->getAggregateElement(RelMaskElt));
2945       }
2946       if (IndexRemap[RelMaskElt] != MaskElt) {
2947         AlreadyCompacted = false;
2948         MaskElt = IndexRemap[RelMaskElt];
2949       }
2950     }
2951   }
2952 
2953   unsigned CompactedWidth = CompactedElts.size();
2954 
2955   // To determine the eventual width (between CompactedWidth and Width), we have
2956   // to consider the other operand. Hence, we return a functor here to delay.
2957   return {0, CompactedWidth,
2958           [ShuffleInput, AlreadyCompacted, Width, VecTy,
2959            CompactedElts = std::move(CompactedElts)](
2960               unsigned PaddedWidth,
2961               IRBuilder<InstSimplifyFolder> &Builder) -> Value * {
2962             // Return original if unchanged to guarantee fixpoint termination.
2963             if (AlreadyCompacted && Width == PaddedWidth)
2964               return ShuffleInput;
2965 
2966             // Pad with poison to reach the requested width.
2967             SmallVector<Constant *, 16> PaddedElts(CompactedElts);
2968             while (PaddedElts.size() < PaddedWidth)
2969               PaddedElts.push_back(PoisonValue::get(VecTy->getElementType()));
